#define MOD 232
#define MAX_M 3141592
#define MAX_W 314

int min_weighted_digit_sum(int M, vector<int> W) {
    vector<int> dp(M, INT_MAX);
    dp[0] = 0;
    for (int i = 0; i < M; i++) {
        for (int j = 0; j < 10; j++) {
            int next = (i * 10 + j) % M;
            dp[next] = min(dp[next], dp[i] + W[j]);
        }
    }
    int sum = 0;
    for (int i = 0; i < M; i++) {
        int Nmin = i;
        int temp = i;
        int len = 0;
        while (temp > 0) {
            temp /= 10;
            len++;
        }
        int F_Nmin = 0;
        temp = i;
        for (int k = len - 1; k >= 0; k--) {
            F_Nmin = (F_Nmin + (temp % 10) * (3141 << (2 * k))) % MOD;
            temp /= 10;
        }
        sum = (sum + F_Nmin) % MOD;
    }
    return sum;
}

